### JavaScript Outbound Payloads for Trace Context Headers

Source: https://github.com/newrelic/node-newrelic/blob/main/test/lib/cross_agent_tests/distributed_tracing/README.md

Illustrates the structure for defining expected and unexpected values for outbound `traceparent` and `tracestate` headers, including New Relic-specific attributes. This section details how to specify exact matches, expected fields, and fields that should not be present.

```json
  "outbound_payloads": [
    {
      "exact": {
        "traceparent.version": "00",
        "traceparent.trace_id": "00000000000000006e2fea0b173fdad0",
        "traceparent.trace_flags": "01",
        "tracestate.tenant_id": "33",
        "tracestate.version": 0,
        "tracestate.parent_type": 0,
        "tracestate.parent_account_id": "33",
        "tracestate.sampled": true,
        "tracestate.priority": 1.123432,
        "newrelic.v": [0, 1],
        "newrelic.d.ty": "App",
        "newrelic.d.ac": "33",
        "newrelic.d.ap": "2827902",
        "newrelic.d.tr": "6E2fEA0B173FDAD0",
        "newrelic.d.sa": true,
        "newrelic.d.pr": 1.1234321
      },
      "expected": [
        "traceparent.parent_id",
        "tracestate.timestamp",
        "tracestate.parent_application_id",
        "tracestate.span_id",
        "tracestate.transaction_id",
        "newrelic.d.ap", 
        "newrelic.d.tx", 
        "newrelic.d.ti", 
        "newrelic.d.id"
      ],
      "unexpected": ["newrelic.d.tk"]
    }
  ]
```

